class Solution:
    def smallestRange(self, nums):
        # brute force: candidate endpoints are values; for each value as low,
        # find minimal high so every list has an element in [low, high].
        import bisect
        all_vals = sorted(set(v for lst in nums for v in lst))
        best = None
        for low in all_vals:
            high = low
            ok = True
            for lst in nums:
                idx = bisect.bisect_left(lst, low)
                if idx == len(lst):
                    ok = False
                    break
                high = max(high, lst[idx])
            if not ok:
                break
            cand = [low, high]
            if best is None or (cand[1] - cand[0] < best[1] - best[0]) or (cand[1] - cand[0] == best[1] - best[0] and cand[0] < best[0]):
                best = cand
        return best

