import heapq
class Solution:
    def smallestRange(self, nums):
        heap = []
        cur_max = -10**18
        for i, lst in enumerate(nums):
            heapq.heappush(heap, (lst[0], i, 0))
            cur_max = max(cur_max, lst[0])
        best = None
        while True:
            low, i, j = heapq.heappop(heap)
            cand = [low, cur_max]
            if best is None or (cand[1] - cand[0] < best[1] - best[0]) or (cand[1] - cand[0] == best[1] - best[0] and cand[0] < best[0]):
                best = cand
            if j + 1 == len(nums[i]):
                break
            nxt = nums[i][j + 1]
            cur_max = max(cur_max, nxt)
            heapq.heappush(heap, (nxt, i, j + 1))
        return best

