var smallestRange = function(nums) {
    // min-heap of [value, listIdx, elemIdx]
    const heap = [];
    const cmp = (a, b) => a[0] - b[0];
    const up = (i) => { while (i > 0) { const p = (i - 1) >> 1; if (cmp(heap[p], heap[i]) <= 0) break; [heap[p], heap[i]] = [heap[i], heap[p]]; i = p; } };
    const down = (i) => { const n = heap.length; while (true) { let l = 2*i+1, r = 2*i+2, m = i; if (l < n && cmp(heap[l], heap[m]) < 0) m = l; if (r < n && cmp(heap[r], heap[m]) < 0) m = r; if (m === i) break; [heap[m], heap[i]] = [heap[i], heap[m]]; i = m; } };
    const push = (v) => { heap.push(v); up(heap.length - 1); };
    const pop = () => { const top = heap[0]; const last = heap.pop(); if (heap.length) { heap[0] = last; down(0); } return top; };
    let curMax = -Infinity;
    for (let i = 0; i < nums.length; i++) { push([nums[i][0], i, 0]); curMax = Math.max(curMax, nums[i][0]); }
    let best = null;
    while (true) {
        const [low, i, j] = pop();
        const cand = [low, curMax];
        if (best === null || (cand[1] - cand[0] < best[1] - best[0]) || (cand[1] - cand[0] === best[1] - best[0] && cand[0] < best[0])) best = cand;
        if (j + 1 === nums[i].length) break;
        const nxt = nums[i][j + 1];
        curMax = Math.max(curMax, nxt);
        push([nxt, i, j + 1]);
    }
    return best;
};
